import { useState } from "react"
import API from "../api/axios"
import { useNavigate } from "react-router-dom"

export default function Signup() {
  const [name,setName]=useState("")
  const [email,setEmail]=useState("")
  const [password,setPassword]=useState("")
  const nav=useNavigate()

  const signup=async()=>{
    await API.post("/auth/user/signup",{name,email,password})
    nav("/login")
  }

  return (
    <div className="flex justify-center items-center h-screen">
      <div className="bg-white p-6 rounded-xl shadow w-80">
        <h2 className="text-xl mb-4">Signup</h2>
        <input className="w-full border p-2 mb-2" placeholder="Name" onChange={e=>setName(e.target.value)} />
        <input className="w-full border p-2 mb-2" placeholder="Email" onChange={e=>setEmail(e.target.value)} />
        <input className="w-full border p-2 mb-2" type="password" placeholder="Password" onChange={e=>setPassword(e.target.value)} />
        <button className="w-full bg-red-600 text-white p-2" onClick={signup}>Signup</button>
      </div>
    </div>
  )
}
